import { Component, ElementRef, QueryList, ViewChild, ViewChildren } from '@angular/core';
import { MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { ChartOptions, ChartType, ChartDataset, Chart, registerables } from 'chart.js';
import { ExportDailyWeather, Weather } from '../../angular-model/weather';
import { RainfallService } from '../../services/rainfall/rainfall.service';

// Register Chart.js components
Chart.register(...registerables);

@Component({
  selector: 'app-rainfall',
  templateUrl: './rainfall.component.html',
  styleUrls: ['./rainfall.component.css']
})
export class RainfallComponent {
  @ViewChildren('chartCanvas') chartCanvases!: QueryList<ElementRef>;
  @ViewChild(MatPaginator)
    paginator!: MatPaginator;
  dataSource1: MatTableDataSource<Weather> = new MatTableDataSource<Weather>();
  columnsToDisplay1 = ['year', 'month', 'averagePrecipitation', 'averageTemperatureC'];
  columnsToDisplayWithExpand = [...this.columnsToDisplay1, 'expand'];
  expandedElement: Weather | null | undefined;
  weatherData: Weather[] = [];
  errorMessage: string = '';
  charts: { [key: number]: Chart } = {};
  pageSize: number = 0;
  pageNo: number = 0;

  constructor(private rainfallService: RainfallService) {
  }

  ngOnInit(): void {
    this.pageSize = 5;
    this.pageNo = 0;
    this.rainfallService.getWeatherData().subscribe(
      (data: Weather[]) => {
        this.weatherData = data;
        debugger;
        this.dataSource1.data = this.weatherData;        
        console.log('Dados do tempo', this.weatherData);        
      },
      (error: any) => {
        this.errorMessage = `Erro ao obter dados do tempo: ${error.message}`;
        console.error('Erro ao obter dados do tempo', error);
      }
    );
  }

  ngAfterViewInit() {
    this.dataSource1.paginator = this.paginator;
  }

  pageEvents(event: any) {
    console.log(event.pageIndex);
    console.log(event.pageSize);
    if (event.pageIndex > this.pageNo) {
      // Clicked on next button
    } else {
      // Clicked on previous button
    }
    // The code that you want to execute on clicking on next and previous buttons will be written here.
  }

  /** Checks whether an element is expanded. */
  public isExpanded(element: Weather) {
    return this.expandedElement === element;
  }

  openModal(daily: ExportDailyWeather): void {
    const day = new Date(daily.infoDate).getDate();
    const month = new Date(daily.infoDate).getMonth();

    let totalElementsWithSimilarDate = this.weatherData.filter(weather =>
      weather.dailyWeatherData.some(daily =>
        new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month
      )
    );
    console.log("parâmetro geral de medição manual no período: ", totalElementsWithSimilarDate.length)

    let validDataValue = this.weatherData.filter(weather =>
      weather.dailyWeatherData.some(daily =>
        new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month
      ) && weather.dailyWeatherData.some(daily => daily.precipitation > 0 || daily.temperatureC > 0)
    );

    console.log("datas desconsideradas por falta de medição manual no período: ", totalElementsWithSimilarDate.length - validDataValue.length)


    const maxTemperature = Math.max(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.temperatureC)
    ));

    console.log("temperatura máxima registrada no período:", maxTemperature);

    const minTemperature = Math.min(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.temperatureC)
    ));
    console.log("temperatura mínima registrada no período:", minTemperature);

    const temperatures = validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.temperatureC)
    );

    const averageTemperature = temperatures.reduce((sum, temp) => sum + temp, 0) / temperatures.length;
    console.log("temperatura média registrada no período:", averageTemperature)


    // Calcular a mediana
    temperatures.sort((a, b) => a - b);
    const mid = Math.floor(temperatures.length / 2);
    const medianTemperature = temperatures.length % 2 !== 0 ? temperatures[mid] : (temperatures[mid - 1] + temperatures[mid]) / 2;
    console.log("Mediana da temperatura:", medianTemperature);

    // Calcular a moda
    const frequency: { [key: number]: number } = {};
    let maxFreq = 0;
    let modeTemperature = temperatures[0];
    for (const temp of temperatures) {
      frequency[temp] = (frequency[temp] || 0) + 1;
      if (frequency[temp] > maxFreq) {
        maxFreq = frequency[temp];
        modeTemperature = temp;
      }
    }
    console.log("Moda da temperatura:", modeTemperature);
  }

  /** Toggles the expanded state of an element. */
  toggle(element: Weather) {
    this.expandedElement = this.isExpanded(element) ? null : element;
    if (this.expandedElement) {
      const pageIndex = this.paginator.pageIndex;
      const pageSize = this.paginator.pageSize;      
      const index = this.weatherData.indexOf(this.expandedElement) - (pageIndex * pageSize);
      if (index !== -1 && this.expandedElement.dailyWeatherData) {
        setTimeout(() => this.prepareChartData(this.expandedElement!.dailyWeatherData, index), 0);
      }
    } else {
      const pageIndex = this.paginator.pageIndex;
      const pageSize = this.paginator.pageSize;
      const index = this.weatherData.indexOf(element) - (pageIndex * pageSize);
      this.charts[index]?.destroy();
      delete this.charts[index];
    }
  }

  shouldHighlightHeader(column: string): boolean {
    if (column === 'precipitation') {
      return this.dataSource1.data.some(daily => daily.averagePrecipitation === 0.000 && daily.averageTemperatureC === 0.0);
    } else if (column === 'temperatureC') {
      return this.dataSource1.data.some(daily => daily.averageTemperatureC === 0.0 && daily.averagePrecipitation === 0.000);
    }
    return false;
  }

  prepareChartData(dailyWeatherData: ExportDailyWeather[], index: number): void {
    const labels: string[] = [];
    dailyWeatherData.forEach(d => {
      const date = new Date(d.infoDate.toString()).getDate().toString()
      labels.push(date);
    });
    
    const temperatureData = dailyWeatherData.map(d => d.temperatureC);
    const precipitationData = dailyWeatherData.map(d => d.precipitation);
    if (this.charts[index]) {
      this.charts[index].destroy();
    }
    const canvas = this.chartCanvases.toArray()[index].nativeElement;

    const firstDate = new Date(dailyWeatherData[0].infoDate);
    const month = firstDate.toLocaleString('default', { month: 'long' });
    const year = firstDate.getFullYear();

    this.charts[index] = new Chart(canvas, {
      type: 'line',
      data: {
        labels: labels,
        datasets: [
          {
            label: 'Temperatura',
            data: temperatureData,
            borderColor: 'red',
            fill: false
          },
          {
            label: 'Precipitação Pluviométrica',
            data: precipitationData,
            borderColor: 'blue',
            fill: false
          }
        ]
      },
      options: {
        responsive: true,
        plugins: {
          title: {
            display: true,
            text: `Gráfico comparativo de oscilações entre temperaturas e precipitações pluviométricas de ${month}/${year} na cidade de Sorocaba/SP - INMET(2024)`
          }
        },
        scales: {
          x: {
            title: {
              display: true,
              text: 'Ano'
            }
          },
          y: {
            beginAtZero: true
          }
        }
      }
    }); 
  }
}
<table mat-table [dataSource]="dataSource1" multiTemplateDataRows class="mat-elevation-z8">
  <ng-container matColumnDef="year">
    <th mat-header-cell *matHeaderCellDef> Ano </th>
    <td mat-cell *matCellDef="let element"> {{element.year}} </td>
  </ng-container>

  <ng-container matColumnDef="month">
    <th mat-header-cell *matHeaderCellDef> Mês </th>
    <td mat-cell *matCellDef="let element"> {{element.month}} </td>
  </ng-container>

  <ng-container matColumnDef="averagePrecipitation">
    <th mat-header-cell *matHeaderCellDef> precipitação pluviométrica (média mm³) </th>
    <td mat-cell *matCellDef="let element">
        {{element.averagePrecipitation | number:'1.3-3'}}
    </td>
  </ng-container>

  <ng-container matColumnDef="averageTemperatureC">
    <th mat-header-cell *matHeaderCellDef> Temperatura (média C°) </th>
    <td mat-cell *matCellDef="let element">
        {{element.averageTemperatureC | number:'1.1-1'}}
    </td>
  </ng-container>

  <ng-container matColumnDef="expand">
    <th mat-header-cell *matHeaderCellDef aria-label="row actions">&nbsp;</th>
    <td mat-cell *matCellDef="let element">
      <button mat-icon-button
              aria-label="expand row"
              (click)="toggle(element); $event.stopPropagation()"
              class="example-toggle-button open-table-item-button"
              [class.example-toggle-button-expanded]="isExpanded(element)">
        <mat-icon>keyboard_arrow_down</mat-icon>
      </button>
    </td>
  </ng-container>

  <ng-container matColumnDef="expandedDetail">
    <td mat-cell *matCellDef="let element" [attr.colspan]="columnsToDisplayWithExpand.length">
      <div class="example-element-detail-wrapper"
           [class.example-element-detail-wrapper-expanded]="isExpanded(element)">        
        <div class="example-element-detail">
          <div>
            <canvas #chartCanvas></canvas>
          </div>
          <div class="example-element-description">           
            <table mat-table [dataSource]="element.dailyWeatherData" class="mat-elevation-z8">              
              <ng-container matColumnDef="infoDate">
                <th mat-header-cell *matHeaderCellDef> Data </th>
                <td mat-cell *matCellDef="let daily"> {{daily.infoDate | date}} </td>
              </ng-container>

              <ng-container matColumnDef="precipitation">
                <th mat-header-cell *matHeaderCellDef> Precipitação </th>
                <td mat-cell *matCellDef="let daily" > {{daily.precipitation | number:'1.3-3'}} </td>
              </ng-container>

              <ng-container matColumnDef="temperatureC">
                <th mat-header-cell *matHeaderCellDef> Temperatura (C°) </th>
                <td mat-cell *matCellDef="let daily"> {{daily.temperatureC | number:'1.1-1'}} </td>
              </ng-container>

              <tr mat-header-row *matHeaderRowDef="['infoDate', 'precipitation', 'temperatureC']"></tr>
              <tr mat-row *matRowDef="let daily; columns: ['infoDate', 'precipitation', 'temperatureC']" (click)="openModal(daily)"></tr>
            </table>
          </div>
        </div>
      </div>
    </td>
  </ng-container>

  <tr mat-header-row *matHeaderRowDef="columnsToDisplayWithExpand"></tr>
  <tr mat-row *matRowDef="let element; columns: columnsToDisplayWithExpand;"
      class="example-element-row"
      [class.example-expanded-row]="isExpanded(element)"
      [ngClass]="{'teste-vermelho': element.averagePrecipitation === 0 && element.averageTemperatureC === 0}"
      (click)="toggle(element)">
  </tr>
  <tr mat-row *matRowDef="let row; columns: ['expandedDetail']" class="example-detail-row"></tr>
</table>

 <mat-paginator class="m-4" [pageSize]="pageSize" [pageIndex]="pageNo"
                [pageSizeOptions]="[5, 12, 24, 100]" (page)="pageEvents($event)">
 </mat-paginator>
